  1	import React, { FC, useRef } from 'react';
  2	import { Trans } from 'react-i18next';
  3	
  4	import { Button, ButtonVariant } from '@patternfly/react-core';
  5	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
  6	
  7	import NetworkPolicySelectorPreview from './components/NetworkPolicySelectorPreview/NetworkPolicySelectorPreview';
  8	import { NetworkPolicyEgressIngress } from './utils/types';
  9	import { getHelpTextPodSelector } from './utils/utils';
 10	import NetworkPolicyConditionalSelector from './NetworkPolicyConditionalSelector';
 11	
 12	type NetworkPolicyPeerSelectorsProps = {
 13	  direction: NetworkPolicyEgressIngress;
 14	  namespaceSelector?: string[][];
 15	  onChange: (podSelector: string[][], namespaceSelector?: string[][]) => void;
 16	  podSelector: string[][];
 17	  policyNamespace: string;
 18	};
 19	
 20	const NetworkPolicyPeerSelectors: FC<NetworkPolicyPeerSelectorsProps> = ({
 21	  direction,
 22	  namespaceSelector,
 23	  onChange,
 24	  podSelector,
 25	  policyNamespace,
 26	}) => {
 27	  const { t } = useNetworkingTranslation();
 28	
 29	  const handlePodSelectorChange = (updated: string[][]) => {
 30	    onChange(updated, namespaceSelector);
 31	  };
 32	
 33	  const handleNamespaceSelectorChange = (updated: string[][]) => {
 34	    onChange(podSelector, updated);
 35	  };
 36	  const podsPreviewPopoverRef = useRef();
 37	
 38	  return (
 39	    <>
 40	      {namespaceSelector && (
 41	        <div className="form-group">
 42	          <NetworkPolicyConditionalSelector
 43	            dataTest="peer-namespace-selector"
 44	            helpText={t(
 45	              'If no namespace selector is provided, pods from all namespaces will be eligible.',
 46	            )}
 47	            onChange={handleNamespaceSelectorChange}
 48	            selectorType="namespace"
 49	            values={namespaceSelector}
 50	          />
 51	        </div>
 52	      )}
 53	      <div className="form-group">
 54	        <NetworkPolicyConditionalSelector
 55	          dataTest="peer-pod-selector"
 56	          helpText={getHelpTextPodSelector(direction, !!namespaceSelector)}
 57	          onChange={handlePodSelectorChange}
 58	          selectorType="pod"
 59	          values={podSelector || []}
 60	        />
 61	      </div>
 62	      <p>
 63	        {direction === 'ingress' ? (
 64	          <Trans t={t}>
 65	            Show a preview of the{' '}
 66	            <Button
 67	              data-test="show-affected-pods-ingress"
 68	              isInline
 69	              ref={podsPreviewPopoverRef}
 70	              variant={ButtonVariant.link}
 71	            >
 72	              affected pods
 73	            </Button>{' '}
 74	            that this ingress rule will apply to.
 75	          </Trans>
 76	        ) : (
 77	          <Trans t={t}>
 78	            Show a preview of the{' '}
 79	            <Button
 80	              data-test="show-affected-pods-egress"
 81	              isInline
 82	              ref={podsPreviewPopoverRef}
 83	              variant={ButtonVariant.link}
 84	            >
 85	              affected pods
 86	            </Button>{' '}
 87	            that this egress rule will apply to.
 88	          </Trans>
 89	        )}
 90	      </p>
 91	      <NetworkPolicySelectorPreview
 92	        dataTest={`pods-preview-${direction}`}
 93	        namespaceSelector={namespaceSelector}
 94	        podSelector={podSelector}
 95	        policyNamespace={policyNamespace}
 96	        popoverRef={podsPreviewPopoverRef}
 97	      />
 98	    </>
 99	  );
100	};
101	
102	export default NetworkPolicyPeerSelectors;

